mepc_setup:       
                  la x26, init
                  csrw 0x341, x26

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x26, 0x9c018f2
                  csrw 0x300, x26 # MSTATUS
                  li x26, 0x6ac4cbbf
                  csrw 0x304, x26 # MIE
                  li x4, 0x8ffffffc
                  li x26, 0x300
                  slli x26, x26, 8
                  addi x26, x26, 0x3
                  sw x26, 0(x4)
                  csrr x26, 0x300
                  sw x26, 0(x4)
                  li x4, 0x8ffffffc
                  li x26, 0x304
                  slli x26, x26, 8
                  addi x26, x26, 0x3
                  sw x26, 0(x4)
                  csrr x26, 0x304
                  sw x26, 0(x4)
                  mret
init:             
                  li x0, 0x1
                  li x1, 0x49ecc087
                  li x2, 0x0
                  li x3, 0x80000000
                  li x4, 0x80000000
                  li x5, 0x0
                  li x6, 0x80000000
