                  li x27, 0xf756e58b
                  li x29, 0xb0c56673
                  li x30, 0xf208cd6c
                  li x31, 0x92492b6
                  la x28, user_stack_end
                  li x4, 0x8ffffffc
                  li x26, 0x0
                  slli x26, x26, 8
                  addi x26, x26, 0x0
                  sw x26, 0(x4)
                  csrr x26, 0x300
                  csrr x4, 0x304
                  csrw 0x300, x26
                  csrw 0x304, x4
                  j main
test_done:        
                  li x4, 0x8ffffff8
                  li x26, 0x0
                  slli x26, x26, 8
                  addi x26, x26, 0x1
                  sw x26, 0(x4)
                  ecall

test_fail:        
                  li x4, 0x8ffffff8
                  li x26, 0x1
                  slli x26, x26, 8
                  addi x26, x26, 0x1
                  sw x26, 0(x4)
                  ecall

